import Tournamentcard from "./Tournamentcard";
import T1 from "./img/tournament/1.jpg";
import T2 from "./img/tournament/2.jpg"

const Tournament =() =>{

    var tor=[
        {
            Headtitle1:" WarCraft",
            Headtitle2:"DOOM",
        }
    ]




    return(
        <section id="tournament">
            <div class="container-fluid">
                <div class="row">
                    <div class="col-12">
                        <div class="text-center py-5">
                            <button class="btntour px-5 py-2 border-0 font2 fw-bold">Tournaments</button>
                        </div>
                    </div>
                </div>
                <div class="container">
                    <div class="row pb-5">
                         <Tournamentcard  title={tor[0].Headtitle1}  image={T1}/>
                         <Tournamentcard  title={tor[0].Headtitle2}  image={T2}/>
                    </div>
                </div>
            </div>
        </section>
    );
}
export default Tournament;