import React from 'react';
import OwlCarousel from 'react-owl-carousel';
import GC5 from "./img/review/GC5.jpg";
import GC6 from "./img/review/GC6.jpg";
import GC7 from "./img/review/GC7.jpg";
import GC8 from "./img/review/GC8.jpg";
import GC9 from "./img/review/GC9.jpg";
import GC10 from "./img/review/GC10.jpg";
import Owlcarouselcard from './Owlcarouselcard';


const Owlcarousel =() =>{

    var game=[
        {
            G1:"Overwatch Halloween",
            G2:"Grand Theft Auto",
            G3:"Avatar",
            G4:"Anthem",
            G5:"Cyberpunk 2077",
            G6:"Spiderman"
        }
    ]


    return(

        <section id='owlcarousel'>
            <div class="container">
                <div class="row py-5">
                    <div class="col-12">

                        <h2 class="text-center pb-3 text-white fw-bold display-6 font2">Upcomming Game</h2>

                        <OwlCarousel className='owl-theme'  autoplay loop
                        responsive= {
                            {
                                '0':{
                                    items: 1
                                },
                                '768': {
                                    items: 2
                                },
                                '1200': {
                                    items: 3
                                }
                            }
                            
                        }
                        >
                            <div class='item'>   
                                <Owlcarouselcard gamename={game[0].G1} imgs={GC5}/>
                            </div>
                            <div class='item'>   
                                <Owlcarouselcard gamename={game[0].G3} imgs={GC7}/>
                            </div>
                            <div class='item'>   
                                <Owlcarouselcard gamename={game[0].G2} imgs={GC6}/>
                            </div>
                            <div class='item'> 
                                <Owlcarouselcard gamename={game[0].G4} imgs={GC8}/>
                            </div>
                            <div class='item'> 
                                <Owlcarouselcard gamename={game[0].G5} imgs={GC9}/>
                            </div>
                            <div class='item'>
                                <Owlcarouselcard gamename={game[0].G6} imgs={GC10}/>
                            </div>
                        </OwlCarousel>
                    </div>
                </div>
            </div>
        </section>
    );
} 
export default Owlcarousel;
