
import Recentreviewcard from "./Recentreviewcard";
import rv1 from "./img/review/rv1.jpg"
import rv2 from "./img/review/rv2.jpg"
import rv3 from "./img/review/rv3.jpg"
import rv4 from "./img/review/rv4.jpg"
const Recentreview =() =>{


    var recent=[
        {
            H1:"Assasin’s Creed",
            H2:"Doom",
            H3:"Overwatch",
            H4:"GTA"
        }
    ]

    return(

        <section id="recentreview">
            <div class="container-fluid">
                <div class="row">
                    <div class="col-12">
                        <div class=" text-center py-5">
                            <a href="#" class="btn btn-danger fs-3 font1 rounded-0 px-3 butt">New</a>   
                            <h2 class="py-5 fw-bold display-3 font2">Recent Review</h2> 
                        </div> 
                    </div>
                </div>
                <div class="container">
                    <div class="row pb-5">
                        <Recentreviewcard name={recent[0].H1} imgs={rv1} />
                        <Recentreviewcard name={recent[0].H2} imgs={rv2}/>
                        <Recentreviewcard name={recent[0].H3} imgs={rv3}/>
                        <Recentreviewcard name={recent[0].H4} imgs={rv4}/>

                    </div>
                </div>
            </div>
        </section>



    );
}
export default Recentreview;