const Latestpostcard =(props) =>{

    return(
        <div class="card mb-3 bg-transparent border-0">
            <div class="row g-0">
                <div class="col-md-4">
                    <img src={props.img} class="img-fluid rounded-start p-3" alt="..."/>
                </div>
                <div class="col-md-8">
                    <div class="card-body">
                     <h5 class="card-title text-warning font2">June 21, 2018</h5>
                    <p class="card-text text-secondary font5">Lorem ipsum dolor sit amet, consectetur adipisc ing ipsum </p>
                    <p class="card-text"><small class="text-muted font7">By Admin</small></p>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Latestpostcard;