import Upcominggamecard from "./Upcominggamecard";
import GC5 from "./img/review/GC5.jpg";
import GC6 from "./img/review/GC6.jpg";
import GC7 from "./img/review/GC7.jpg";
import GC8 from "./img/review/GC8.jpg";
import GC9 from "./img/review/GC9.jpg";
import GC10 from "./img/review/GC10.jpg";

const Upcominggame =() =>{

    var game=[
        {
            G1:"Overwatch Halloween",
            G2:"Grand Theft Auto",
            G3:"Avatar",
            G4:"Anthem",
            G5:"Cyberpunk 2077",
            G6:"Spiderman"
        }
    ]

    return(
        <section>
            <div class="container-fluid">
                <div class="row">
                    <div class="col-12 p-0">
                        <h2 class="text-center py-5 fw-bold display-6 font2">Upcomming Game</h2>
                    </div>
                </div>

                <div class="row">
                    <div class="col-12 col-md-6 my-5">
                        <Upcominggamecard gamename={game[0].G1} imgs={GC5}/>
                    </div>    
                    <div class="col-12 col-md-6 my-5">
                        <Upcominggamecard gamename={game[0].G2} imgs={GC6}/>
                    </div>
                    <div class="col-12 col-md-6 my-5">
                        <Upcominggamecard gamename={game[0].G3} imgs={GC7}/>
                    </div>
                    <div class="col-12 col-md-6 my-5">
                        <Upcominggamecard gamename={game[0].G4} imgs={GC8}/>
                    </div>
                    <div class="col-12 col-md-6 my-5">
                        <Upcominggamecard gamename={game[0].G5} imgs={GC9}/>
                    </div>
                    <div class="col-12 col-md-6 my-5">    
                    <Upcominggamecard gamename={game[0].G6} imgs={GC10}/>
                    </div>
                </div>
            </div>
        </section>
    );
}
export default Upcominggame;