import Topcommentscard from "./Topcommentscard";
import A1 from "./img/authors/A1.jpg";
import A2 from "./img/authors/A2.jpg";
import A3 from "./img/authors/A3.jpg";

const Topcomments =() =>{


    return(
        <div class="col-12 col-md-6 col-lg-4">
            <div class="card  topcomments rounded-0">
                <div class="card-body">
                    <h2 class="card-title text-white py-2 font1">TOP COMMENTS</h2>
                </div>
                <>
                <Topcommentscard img={A1}/>
                <Topcommentscard img={A2}/>
                <Topcommentscard img={A3}/>
                </>
            </div>
        </div>
    );
}

export default Topcomments;