import Latestpostcard from "./Latestpostcard";
import L1 from "./img/latest-blog/L1.jpg";
import L2 from "./img/latest-blog/L2.jpg";
import L3 from "./img/latest-blog/L3.jpg";

const Latestpost =() =>{


    return(
        <div class="col-12 col-md-6 col-lg-4 my-2 my-md-0">
            <div class="card  latestpost rounded-0">
                <div class="card-body">
                    <h2 class="card-title text-white py-2 font1">LATEST POST</h2>
                </div>
                <>
                <Latestpostcard img={L1} />
                <Latestpostcard img={L2} />
                <Latestpostcard img={L3} />
                </>
            </div>
        </div>
    );
}

export default Latestpost;