import React from "react";
import logo from './img/logo.png';
import { Link } from "react-router-dom";
const Navbar = () =>{

    return(
        <section id="navbar">
            <div class="container-fluid">
                <div class="row">
                    <div class="col-12 p-0">
                    <nav class="navbar navbar-expand-lg bg-dark">
                        <div class="container-fluid py-2">
                            <a class="navbar-brand ms-5 " href="#"><img src={logo}/></a>
                            <button class="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
                            <span class="navbar-toggler-icon"></span>
                            </button>
                            <div class="collapse navbar-collapse" id="navbarSupportedContent">
                            <ul class="navbar-nav m-auto mb-2 mb-lg-0">
                                <li class="nav-item">
                                <Link class="nav-link text-white fs-5 px-4 font2" to='/Home'>Home</Link>
                                </li>
                                <li class="nav-item">
                                <Link class="nav-link text-white fs-5 px-4 font2" to='/Game'>Game</Link>
                                </li>
                                <li class="nav-item">
                                <Link class="nav-link text-white fs-5 px-4 font2" to='/BLog'>Blog</Link>
                                </li>
                                <li class="nav-item">
                                <Link class="nav-link text-white fs-5 px-4 font2" to='/Forums'>Forums</Link>
                                </li>
                                <li class="nav-item ">
                                <Link class="nav-link text-white fs-5 px-4 font2" to='/Contact'>Contacts</Link>
                                </li>
                            </ul>
                            <Link class="btn btn-outline-warning rounded-pill me-5 font2" to='/Contact'>Login/Register</Link>
                            </div>
                        </div>
                        </nav>
                    </div>
                </div>

            </div>
        </section>
    );
}

export default Navbar;