const Tournamentcard =(props) =>{
    return(
        <div class="col-12 col-lg-6">
            <div class="card mb-3 tour">
              <div class="row g-0">
                <div class="col-md-4 d-flex flex-column justify-content-center align-items-center">
                    <img src={props.image} class="img-fluid  rounded-start" alt="..."/>
                </div>
               <div class="col-md-8">
                 <div class="card-body spancolor">
                  <h2 class="card-text text-warning fs-1 py-3 font1">{props.title}</h2>
                  <p class="card-text font6"> <span>Tournament Beggins:</span> June 20, 2018</p>
                  <p class="card-text font6"> <span>Tounament Ends:</span> July 01, 2018</p>
                  <p class="card-text font6"><span>Participants:</span> 10 teams</p>
                  <p class="card-text font6"><span>Tournament Author:</span> Admin</p>
                  <p class="card-text text-secondary py-3 font6"> <span class="text-warning">Prizes:</span> 1st place $2000, 2nd place: $1000, 3rd place: $500</p>
                 </div>
               </div>
              </div>
           </div>
        </div>

    );
}
export default Tournamentcard;